import{_ as o,o as d,c,a0 as t}from"./chunks/framework.CWk8AOcY.js";const h=JSON.parse('{"title":"CubeSandbox 运维手册（章节版，源码校对）","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/ops-manual/README.md","filePath":"zh/guide/ops-manual/README.md"}'),l={name:"zh/guide/ops-manual/README.md"};function a(i,e,r,n,s,u){return d(),c("div",null,[...e[0]||(e[0]=[t('<h1 id="cubesandbox-运维手册-章节版-源码校对" tabindex="-1">CubeSandbox 运维手册（章节版，源码校对） <a class="header-anchor" href="#cubesandbox-运维手册-章节版-源码校对" aria-label="Permalink to &quot;CubeSandbox 运维手册（章节版，源码校对）&quot;">​</a></h1><p>这套手册面向已经在维护或即将上线 <code>CubeSandbox</code> 的同学，重点覆盖<strong>实际部署链路中的运维组件</strong>，而不是只罗列仓库目录。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><p>本文按源码、安装脚本和 one-click 运行时行为整理，覆盖以下内容：</p><ul><li>控制面：<code>CubeMaster</code>、<code>CubeAPI</code>、<code>support(MySQL/Redis)</code>、<code>CubeProxy</code>、<code>CoreDNS</code>、<code>WebUI</code></li><li>节点面：<code>Cubelet</code>、<code>network-agent</code>、<code>CubeShim</code>、<code>cube-runtime</code></li><li>运维入口：<code>install.sh</code>、<code>install-compute.sh</code>、<code>up*.sh</code>、<code>down*.sh</code>、<code>smoke.sh</code>、<code>quickcheck.sh</code></li><li>命令行入口：<code>cubemastercli</code>、<code>cubecli</code>、<code>cube-runtime</code></li><li>关键配置：仓库模板、安装后配置、运行时生成文件、健康检查与日志路径</li></ul><h2 id="阅读顺序" tabindex="-1">阅读顺序 <a class="header-anchor" href="#阅读顺序" aria-label="Permalink to &quot;阅读顺序&quot;">​</a></h2><ol><li><a href="./01-command-reference.html">命令总览与 CLI 参考</a>：所有主要命令与 CLI 入口</li><li><a href="./02-control-plane-config.html">控制面配置文件路径与说明</a>：控制面组件配置文件路径与说明</li><li><a href="./03-node-runtime-config.html">节点与运行时配置文件路径与说明</a>：节点侧与运行时配置文件路径与说明</li><li><a href="./04-install-layout-and-generated-files.html">安装目录、生成文件与落盘路径</a>：安装目录、生成文件、落盘路径</li><li><a href="./05-logs-health-and-troubleshooting.html">日志、健康检查与排障</a>：日志、巡检、排障</li></ol><h2 id="本手册的-全量-边界" tabindex="-1">本手册的“全量”边界 <a class="header-anchor" href="#本手册的-全量-边界" aria-label="Permalink to &quot;本手册的“全量”边界&quot;">​</a></h2><p>这里的“全量”指<strong>已部署系统需要维护的组件和命令入口</strong>，不包含：</p><ul><li>仅用于测试的 mock、benchmark、示例程序</li><li><code>hypervisor/</code> 内大量上游 Cloud Hypervisor 开发文档</li><li>与生产运行无直接关系的实验目录</li></ul><p>如果后续要整理成 CubeSandbox 文档网站，建议以本目录作为运维专区初稿，再补：</p><ul><li>中英双语版本</li><li>站点导航（sidebar / routes）</li><li>FAQ / Runbook / 变更记录（release-based）</li></ul><h2 id="组件主配置入口速查" tabindex="-1">组件主配置入口速查 <a class="header-anchor" href="#组件主配置入口速查" aria-label="Permalink to &quot;组件主配置入口速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组件</th><th>仓库内主配置</th><th>安装后主路径</th><th>说明</th></tr></thead><tbody><tr><td>one-click 全局环境</td><td><code>deploy/one-click/env.example</code></td><td><code>/usr/local/services/cubetoolbox/.one-click.env</code></td><td>控制部署角色、端口、依赖容器、代理/DNS/WebUI 等</td></tr><tr><td>CubeMaster</td><td><code>configs/single-node/cubemaster.yaml</code></td><td><code>/usr/local/services/cubetoolbox/CubeMaster/conf.yaml</code></td><td>控制面调度、日志、MySQL/Redis、模板默认请求</td></tr><tr><td>Cubelet</td><td><code>Cubelet/config/config.toml</code></td><td><code>/usr/local/services/cubetoolbox/Cubelet/config/config.toml</code></td><td>节点核心静态配置</td></tr><tr><td>Cubelet 动态配置</td><td><code>Cubelet/dynamicconf/conf.yaml</code></td><td><code>/usr/local/services/cubetoolbox/Cubelet/dynamicconf/conf.yaml</code></td><td>节点配额、GC、meta server 接入</td></tr><tr><td>network-agent</td><td><code>configs/single-node/network-agent.yaml</code></td><td><code>/usr/local/services/cubetoolbox/network-agent/network-agent.yaml</code></td><td>仅保存基础监听信息；运行时以 flag + Cubelet 配置为准</td></tr><tr><td>CubeShim 运行时</td><td><code>deploy/one-click/config-cube.toml</code></td><td><code>/usr/local/services/cubetoolbox/cube-shim/conf/config-cube.toml</code></td><td>运行时资产路径契约</td></tr><tr><td>CubeAPI</td><td>无独立 yaml/toml</td><td>读取 <code>/usr/local/services/cubetoolbox/.one-click.env</code></td><td>通过 env + CLI flag 叠加配置</td></tr><tr><td>support</td><td><code>deploy/one-click/support/docker-compose.yaml.template</code></td><td><code>/usr/local/services/cubetoolbox/support/docker-compose.yaml</code></td><td>MySQL / Redis</td></tr><tr><td>CubeProxy</td><td><code>deploy/one-click/cubeproxy/global.conf.template</code></td><td><code>/usr/local/services/cubetoolbox/cubeproxy/global.conf</code></td><td>Redis、节点 IP、证书挂载</td></tr><tr><td>CoreDNS</td><td><code>deploy/one-click/coredns/Corefile.template</code></td><td><code>/usr/local/services/cubetoolbox/coredns/Corefile</code></td><td><code>cube.app</code> 域名应答与上游转发</td></tr><tr><td>WebUI</td><td><code>deploy/one-click/webui/nginx.conf</code></td><td><code>/usr/local/services/cubetoolbox/webui/nginx.generated.conf</code></td><td>静态资源服务与 <code>/cubeapi</code> 反代</td></tr></tbody></table><h2 id="源码依据" tabindex="-1">源码依据 <a class="header-anchor" href="#源码依据" aria-label="Permalink to &quot;源码依据&quot;">​</a></h2><p>本手册基于以下入口逐项校对：</p><ul><li><code>deploy/one-click/README_zh.md</code></li><li><code>deploy/one-click/install.sh</code></li><li><code>deploy/one-click/scripts/one-click/*.sh</code></li><li><code>CubeMaster/cmd/cubemastercli/**</code></li><li><code>Cubelet/cmd/cubecli/**</code></li><li><code>CubeShim/cube-runtime/**</code></li><li><code>CubeAPI/src/**</code></li><li><code>network-agent/cmd/network-agent/main.go</code></li><li><code>Cubelet/config/config.toml</code></li><li><code>Cubelet/dynamicconf/conf.yaml</code></li><li><code>configs/single-node/cubemaster.yaml</code></li><li><code>configs/single-node/network-agent.yaml</code></li></ul>',17)])])}const m=o(l,[["render",a]]);export{h as __pageData,m as default};
